"""
MKT Christ Layer — Jeremiah chapters 37–40
Run: python3 scripts/zc-christ-jeremiah-37-40-fill.py

Ch 37–38: Jeremiah's imprisonment — parallel to Jesus's arrest, trial, and imprisonment.
Ch 39: The fall of Jerusalem — parallel to the judgment Jesus announced.
Ch 40: Gedaliah's brief government — the aftermath that points forward.

Key Christological pivots:
- 37:12-15: Jeremiah arrested on false charges / beaten / imprisoned — closely
  parallels Jesus's arrest, false charge of defection/sedition, and imprisonment.
- 37:17-20: Jeremiah before Zedekiah (private) asking for mercy — Jesus before
  Pilate: the judge who knows the prisoner's innocence but won't act.
- 38:4-5: Officials demand death; Zedekiah says 'he is in your hands' — Pilate's
  'I find no guilt in him' / hand-washing (Matt 27:24-26; Luke 23:4).
- 38:6: Cast into the cistern/pit — the death-pit of Psalms (Ps 28:1; 40:2;
  88:6); the Joseph-in-the-pit type (Gen 37:24) fulfilled in Christ's descent.
- 38:2: 'Whoever surrenders will live; whoever stays will die' — the gospel
  paradox of death-through-resistance vs. life-through-surrender (Matt 16:25).
- 39:15-18: Ebed-melech saved 'because you trusted in me' — salvation by faith;
  the foreigner who trusts YHWH receives the same rescue as the covenant people.
- 40:2-3: The Babylonian commander understands YHWH's justice — the centurion
  at the cross ('truly this man was the Son of God', Matt 27:54).
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

JER_CHRIST = {
  "37": {
    "1": "<p>Zedekiah is installed as king over Coniah — the man who came after the throne-cursed Jehoiachin. The succession through puppet-kingship is the political vacuum that the Righteous Branch oracle (23:5-6) addresses: the legitimate Davidic line has been broken through exile and curse; the throne is now occupied by a Babylonian vassal. Jesus fills this vacuum: he is the one in whom the legitimate Davidic throne-right is finally and permanently established (Luke 1:32-33), not through political succession but through resurrection and ascension.</p>",
    "2": "<p>&apos;But he, his servants, and the people of the land refused to listen to the words of the LORD.&apos; The persistent not-listening that characterizes Jeremiah&apos;s entire ministry reaches its climax under Zedekiah. Jesus encounters the same refusal: &apos;Though he had performed so many signs before them, they still would not believe in him&apos; (John 12:37). The pattern — YHWH sends his word; the people refuse — culminates in the rejection of the Word made flesh (John 1:11).</p>",
    "3": "<p>Zedekiah sends for Jeremiah to &apos;inquire of the LORD our God.&apos; The king who will not obey the word still wants the prophet&apos;s intercession. Jesus is the great intercessor: &apos;he always lives to intercede for them&apos; (Heb 7:25). But his intercession is not magic that overrides covenant accountability — like Jeremiah, he continues to speak truth to those who will not hear it. The intercession is genuine only where there is genuine turning (John 17 shows his intercession for those who do believe).</p>",
    "4": "<p>Jeremiah still moving freely — not yet imprisoned. The pre-arrest phase of the prophet&apos;s ministry. Jesus&apos;s public ministry of free movement — teaching in the temple, healing in the streets — precedes his arrest. Both prophets have a period of freedom followed by imprisonment at the hands of the civil and religious establishment.</p>",
    "5": "<p>Pharaoh&apos;s army comes out from Egypt, and the Chaldeans temporarily lift the siege. The temporary relief that the unreliable Egyptian alliance provides. Jesus warns his disciples against trusting in political alliances and military strength: &apos;do not put your trust in princes, in human beings, who cannot save&apos; (Ps 146:3, cited by Jesus&apos;s disciples in Acts 5:38-39 context). The Egyptian army that seems to help will not ultimately deliver.</p>",
    "6": "<p>The word of the LORD comes to Jeremiah even in the midst of the political crisis. Jesus&apos;s teaching is similarly uninterrupted by political pressure: &apos;I must proclaim the good news of the kingdom of God to the other towns also, because that is why I was sent&apos; (Luke 4:43). The prophetic word continues regardless of political circumstances.</p>",
    "7": "<p>&apos;Say to the king: Pharaoh&apos;s army... will return to Egypt its own land.&apos; The message of the Egyptian alliance&apos;s unreliability. Jesus&apos;s consistent teaching: do not build on sand (Matt 7:26-27); do not lay up earthly treasures (Matt 6:19-21); the things that seem like solid help will collapse. The Egyptian army&apos;s retreat is the enacted parable of all worldly security.</p>",
    "8": "<p>The Chaldeans will return and capture the city and burn it. The certainty of judgment despite the temporary reprieve. Jesus&apos;s warnings about Jerusalem are similarly certain despite the long delay: &apos;the days will come upon you when your enemies will build an embankment against you and encircle you... they will not leave one stone on another&apos; (Luke 19:43-44). The judgment postponed is not the judgment cancelled.</p>",
    "9": "<p>&apos;Do not deceive yourselves by saying: the Chaldeans will certainly leave us, for they will not leave.&apos; Self-deception about one&apos;s safety. Jesus warns against the same: &apos;many will say to me on that day, Lord, Lord, did we not prophesy in your name...? Then I will tell them plainly: I never knew you&apos; (Matt 7:22-23). The self-deception of assumed safety without genuine covenant relationship is the most dangerous deception.</p>",
    "10": "<p>&apos;Even if you had defeated the entire Chaldean army and only the wounded were left, they would rise and burn this city.&apos; The hyperbolic impossibility — even a catastrophically defeated Babylon would still prevail. The inevitability of the judgment is complete. At the cross, Jesus endures what seems like the defeat of good by evil — and the resurrection is the &apos;rising of the wounded&apos; in a different sense: the one who is mortally wounded rises, and through his rising all previous calculations are overturned.</p>",
    "11": "<p>The Chaldean army withdrawing because of Pharaoh&apos;s army — the narrative moment of false hope. False hope is the setting for Jeremiah&apos;s arrest: he attempts to go to Benjamin during what looks like a respite, and is seized. Similarly, the disciples&apos; hope at the resurrection rumors becomes real hope only at the actual appearance of the risen Jesus — before that, the &apos;respite&apos; of the empty tomb generates confusion rather than certainty (John 20:9: &apos;they still did not understand from Scripture that Jesus had to rise from the dead&apos;).</p>",
    "12": "<p>Jeremiah sets out toward the territory of Benjamin — likely to Anathoth, his hometown, to receive his share of a property transaction. The mundane purpose of the journey: personal legal business. The innocence of the errand makes the arrest more striking. Jesus&apos;s arrest also comes during ordinary activity — praying in a garden with his disciples (Luke 22:39-46). The violent arrest intrudes into the normal.</p>",
    "13": "<p>&apos;When he reached the Benjamin Gate, a sentinel arrested him saying: You are defecting to the Chaldeans!&apos; The false charge. Jesus was arrested on the charge that he claimed to be the king of the Jews (Luke 23:2-3) and that he stirred up the people (Luke 23:5) — similarly false or distorted accusations. The innocent prophet and the innocent Son of God both face trumped-up political charges designed to justify their imprisonment.</p>",
    "14": "<p>&apos;Jeremiah replied: That is not true! I am not defecting to the Chaldeans. But Irijah refused to listen to him.&apos; The denial of the false charge is ignored. Jesus also denies being what his accusers charge: &apos;my kingdom is not of this world; if it were, my servants would fight&apos; (John 18:36) — the denial of the political-insurrectionist charge. But the authorities proceed regardless. The innocence of the accused does not prevent the judicial process when the conclusion has been predetermined.</p>",
    "15": "<p>&apos;The officials were furious with Jeremiah. They had him beaten and imprisoned in the house of Jonathan the secretary.&apos; Beaten, then imprisoned in a vaulted dungeon. Jesus was beaten (John 19:1-3: flogged, crown of thorns, struck) and imprisoned overnight before crucifixion. The beating of the prophet at the hands of officials is the pattern fulfilled in the Son — both punishments are unjust, both are inflicted by those who should have known better.</p>",
    "16": "<p>Jeremiah in the vaulted dungeon cell — the underground pit (<em>beit habor</em>, the house of the pit). The pit is the OT imagery of death (Ps 28:1; 30:3; 40:2; 88:6: &apos;I am counted among those who go down to the pit&apos;). Jesus&apos;s descent into death is the fulfillment of all pit-imagery: 1 Pet 3:18-20 (&apos;he went and made proclamation to the imprisoned spirits&apos;); Eph 4:9 (&apos;he descended to the lower, earthly regions&apos;). The pit of Jeremiah&apos;s dungeon is the shadow of the death-pit into which the Son descends.</p>",
    "17": "<p>&apos;King Zedekiah sent for him and questioned him privately: Is there a word from the LORD?&apos; The private consultation — the king who will not obey publicly seeks divine guidance privately. Pilate&apos;s private consultation with Jesus (John 18:33-38: &apos;are you the king of the Jews?&apos; — the private questioning) follows the same pattern. Both rulers privately acknowledge the prophet-king&apos;s authority while publicly capitulating to the demands of the crowd.</p>",
    "18": "<p>&apos;What wrong have I done to you, your servants, or this people, that you have thrown me into prison?&apos; The self-defense of the innocent prisoner. Jesus before Annas: &apos;I have spoken openly to the world... why do you ask me? Question those who heard me&apos; (John 18:20-21). Both Jeremiah and Jesus appeal to the absence of offense — their teaching has been public and consistent; their imprisonment is without just cause.</p>",
    "19": "<p>&apos;And where are your prophets who prophesied: the king of Babylon will not attack you?&apos; The false prophets have been proven wrong; only the true prophet who predicted judgment has been vindicated. Jesus&apos;s own predictions come true despite opposition: &apos;I told you, and you do not believe. The works that I do in my Father&apos;s name bear witness about me&apos; (John 10:25). The vindication of the true prophet comes through the fulfillment of what he predicted.</p>",
    "20": "<p>Jeremiah pleads with the king not to send him back to the dungeon, where he will die. The prophet&apos;s vulnerability — he can be killed by the king&apos;s whim. Jesus also was at the mercy of those with earthly authority: &apos;do you refuse to speak to me? Do you not know that I have authority to release you and authority to crucify you?&apos; (John 19:10). Both Pilate&apos;s authority and Zedekiah&apos;s authority are real within their limits — but both are ultimately derivative (John 19:11: &apos;you would have no power over me if it were not given to you from above&apos;).</p>",
    "21": "<p>Zedekiah gives the order: Jeremiah transferred to the court of the guard, given bread daily until all the bread was gone. The minimal provision — enough to live on, not enough to be comfortable. Jesus provides the bread that sustains more deeply: &apos;I am the bread of life; whoever comes to me will never go hungry&apos; (John 6:35). The daily bread given to the imprisoned prophet is a shadow of the bread that the Son gives from his own person.</p>"
  },
  "38": {
    "1": "<p>The four officials who hear Jeremiah&apos;s preaching and bring a capital charge: the officials aligned with the court faction that wants submission-without-repentance. The institutional opposition to the prophet mirrors the Sanhedrin&apos;s opposition to Jesus: &apos;the chief priests and elders of the people assembled in the palace of the high priest, who was called Caiaphas, and they schemed to arrest Jesus secretly and kill him&apos; (Matt 26:3-4).</p>",
    "2": "<p>&apos;Whoever stays in this city will die by sword, famine, or pestilence. But whoever goes out and surrenders to the Chaldeans will live.&apos; The gospel paradox embedded in the siege oracle: surrender is life; resistance is death. Jesus inverts the world&apos;s wisdom in the same way: &apos;whoever wants to save their life will lose it, but whoever loses their life for my sake will find it&apos; (Matt 16:25; Mark 8:35; Luke 9:24). The covenant logic of 38:2 — surrender and live — is the same logic as dying with Christ to live with him (Rom 6:8; 2 Tim 2:11).</p>",
    "3": "<p>&apos;This city will certainly be handed over to the army of the king of Babylon, and he will capture it.&apos; The certainty of the judgment. Jesus announces the same certainty about Jerusalem: &apos;they will dash you to the ground, you and your children within you ... because you did not recognize the time of your visitation&apos; (Luke 19:44). The &apos;visit&apos; that was not recognized — Jeremiah&apos;s word in 609-586 BCE; Jesus&apos;s presence in 30 CE; both unrecognized, both followed by the same consequence.</p>",
    "4": "<p>&apos;This man must be put to death. He is demoralizing the soldiers who remain in this city and all the people, by speaking such words.&apos; The capital charge: demoralizing the defense. The Sanhedrin&apos;s charge against Jesus: &apos;we have found this man subverting our nation. He opposes payment of taxes to Caesar and claims to be Messiah, a king&apos; (Luke 23:2). Both Jeremiah and Jesus are accused of undermining the social order rather than heard for what they are actually saying — both are framed as political threats rather than prophetic truth-tellers.</p>",
    "5": "<p>&apos;King Zedekiah replied: He is in your hands, for the king can do nothing against you.&apos; Zedekiah&apos;s political capitulation: he privately believes Jeremiah (37:17) but publicly hands him over to those who want him dead. Pilate similarly knows Jesus is innocent (Luke 23:4, 14, 22: &apos;I find no basis for a charge against this man&apos;) but washes his hands and hands him over (Matt 27:24-26). Both Zedekiah and Pilate are men of compromised authority who surrender the innocent to unjust execution to preserve their own position.</p>",
    "6": "<p>&apos;They took Jeremiah and threw him into the cistern of Malchiah ... in the court of the guard. They lowered Jeremiah by ropes into the cistern, which had no water but only mud; and Jeremiah sank in the mud.&apos; The cistern-pit — the death-place. Three great types converge: Joseph thrown into the pit by his brothers (Gen 37:24); the pit-psalms of descent to Sheol (Ps 40:2: &apos;he lifted me out of the slimy pit, out of the mud and mire&apos;); and the cross itself. Jesus&apos;s descent into death is the ultimate cistern-plunge. His resurrection is the &apos;lifting out of the pit&apos; that Ps 40:2 celebrates and that Jeremiah&apos;s rescue (v. 13) prefigures.</p>",
    "7": "<p>Ebed-melech the Ethiopian — a foreigner, a court official, not a member of the covenant people — is the one who hears of Jeremiah&apos;s plight and acts. The foreigner who cares for the prophet while the covenant people have abandoned him. This mirrors the NT pattern: the Roman centurion whose faith Jesus marvels at (Matt 8:10: &apos;I have not found such great faith even in Israel&apos;); the Samaritan who helps where the priest and Levite pass by (Luke 10:33); the Syrophoenician woman (Mark 7:26-30). The outsider often sees what the insider has missed.</p>",
    "8": "<p>Ebed-melech goes to the king to speak on Jeremiah&apos;s behalf. The intercessory act — one person standing before the king to plead for another. Jesus&apos;s high-priestly intercession is in this tradition: &apos;he always lives to intercede for them&apos; (Heb 7:25); &apos;we have an advocate with the Father — Jesus Christ, the Righteous One&apos; (1 John 2:1). The one who pleads before the king on behalf of those in the pit.</p>",
    "9": "<p>&apos;These men have done wrong in everything they did to Jeremiah the prophet by throwing him into the cistern.&apos; Ebed-melech names the injustice plainly — the &apos;they have done wrong&apos; that no Judean official was willing to say. At the cross, the penitent thief names the injustice: &apos;this man has done nothing wrong&apos; (Luke 23:41). The foreigner — the Ethiopian court official, the Jewish criminal on a cross — is the one who tells the truth about the innocent person&apos;s unjust treatment.</p>",
    "10": "<p>The king commands Ebed-melech to take thirty men and pull Jeremiah out before he dies. The rescue authorized from above — the very authority that allowed the imprisonment now authorizes the rescue. Jesus&apos;s resurrection is authorized by the Father who had the authority to &apos;lay down&apos; and &apos;take up again&apos; (John 10:18: &apos;no one takes it from me, but I lay it down of my own accord. I have authority to lay it down and authority to take it up again. This command I received from my Father&apos;).</p>",
    "11": "<p>Ebed-melech takes old rags from the storeroom to cushion the ropes. The practical care — using what is available, attending to the prisoner&apos;s physical comfort even in the rescue operation. Joseph of Arimathea and Nicodemus show the same practical care for Jesus&apos;s body: fine linen, seventy-five pounds of spices, a new tomb (John 19:38-42). The care for the body of the imprisoned/dead prophet is itself a form of confession — that this person matters, that their body deserves dignity.</p>",
    "12": "<p>Ebed-melech calls to Jeremiah: &apos;Put these old rags under your armpits to pad the ropes.&apos; The thoughtful instruction — rescue that attends to the pain of the process. The angels at the empty tomb speak gently to the frightened women (Matt 28:5-7; Mark 16:6-7; Luke 24:4-7) — the messengers of rescue also communicate care and instruction, not just triumph.</p>",
    "13": "<p>&apos;They pulled Jeremiah up with the ropes and lifted him out of the cistern. And Jeremiah remained in the court of the guard.&apos; The lifting-out of the pit. Ps 40:2-3: &apos;he lifted me out of the slimy pit, out of the mud and mire; he set my feet on a rock and gave me a firm place to stand. He put a new song in my mouth, a hymn of praise to our God.&apos; This psalm is applied to Jesus in Heb 10:5-7 (quoting Ps 40:6-8 about doing God&apos;s will). The lifting-from-the-pit is the resurrection pattern.</p>",
    "14": "<p>Zedekiah summons Jeremiah to a secret meeting at the temple — the third private consultation. The king keeps seeking truth but is unwilling to act on it. Nicodemus&apos;s night visit to Jesus (John 3:1-15) is the NT parallel: a leader who seeks the truth privately but cannot yet act publicly. Both Zedekiah and Nicodemus eventually show some courage (Zedekiah protects Jeremiah slightly; Nicodemus helps with the burial, John 19:39-40), but neither fully commits while there is still time to make a difference.</p>",
    "15": "<p>&apos;If I tell you, you will certainly put me to death. And if I give you counsel, you will not listen.&apos; Jeremiah&apos;s honest assessment of the conversation&apos;s limits. Jesus to Pilate: &apos;my kingdom is not of this world&apos; (John 18:36); &apos;you would have no power over me if it were not given to you from above&apos; (John 19:11). Both the prophet and the Son speak truth to those who hold their lives in their hands — not tailoring the message to gain safety.</p>",
    "16": "<p>Zedekiah swears by YHWH not to kill Jeremiah or hand him over to those who want his life. The oath by YHWH — the most solemn promise a Judean king can make. Yet oaths made to protect Christ&apos;s prophets are routinely broken: Herod&apos;s oath that costs John the Baptist his head (Mark 6:26); Pilate&apos;s declaration of innocence that leads to the crucifixion. Human oaths to protect the prophet/Son are insufficient against the pressure of the moment.</p>",
    "17": "<p>&apos;If you will go out and surrender to the king of Babylon&apos;s officials, you will live, the city will not be burned, and your family will survive.&apos; The repeated offer: surrender and live. The gospel pattern again — Jeremiah offers the king the same choice that 38:2 offered the people. Jesus offers the same: &apos;whoever loses their life for my sake will find it&apos; (Matt 16:25). The choice is repeated until the final moment of decision.</p>",
    "18": "<p>&apos;But if you refuse to surrender, this city will be handed over to the Babylonians and burned, and you yourself will not escape.&apos; The consequence of refusing the offer. The Parable of the Wedding Banquet (Matt 22:1-14): those who refuse the invitation and harm the messengers face destruction. The offer of surrender/acceptance is not merely generous — its refusal has real and catastrophic consequences.</p>",
    "19": "<p>Zedekiah&apos;s fear of the Judeans who have already defected to the Chaldeans — he fears human mockery more than YHWH&apos;s word. The fear of human opinion over divine command is the basic failure of those who reject Jesus: &apos;yet at the same time many even among the leaders believed in him. But because of the Pharisees they would not openly acknowledge their faith for fear they would be put out of the synagogue; for they loved human praise more than praise from God&apos; (John 12:42-43).</p>",
    "20": "<p>&apos;They will not hand you over. Obey the voice of the LORD in what I am telling you and it will go well with you, and your life will be spared.&apos; The promise of life through obedience. Jesus: &apos;if you love me, keep my commands ... whoever has my commands and keeps them is the one who loves me. The one who loves me will be loved by my Father, and I too will love them and show myself to them&apos; (John 14:15, 21). The life-through-obedience promise of the prophetic word is fulfilled in the new covenant relationship through Christ.</p>",
    "21": "<p>&apos;But if you refuse to surrender, this is what the LORD has revealed to me.&apos; The alternative path and its revelation. Jesus is the one in whom all divine revelation is concentrated: &apos;no one knows the Father except the Son and those to whom the Son chooses to reveal him&apos; (Matt 11:27). The revealed word that Jeremiah passes from YHWH to Zedekiah is a shadow of the full revelation Christ brings of the Father&apos;s purposes.</p>",
    "22": "<p>The women of the palace mocking the fallen king with their song: &apos;your trusted friends have led you astray and prevailed against you; your feet are sunk in the mud.&apos; The mud-sinking image connects back to Jeremiah&apos;s cistern (38:6): the king who sent the prophet into the mud will himself be depicted as sinking in mud. The reversal of fortunes — the one who imposed suffering receives it. Jesus&apos;s principle: &apos;with the measure you use, it will be measured to you&apos; (Matt 7:2; Luke 6:38).</p>",
    "23": "<p>Wives and children brought out to the Chaldeans; Zedekiah captured. The comprehensive loss of everything he tried to protect by refusing surrender. The discipleship cost: &apos;anyone who loves their father or mother more than me is not worthy of me; anyone who loves their son or daughter more than me is not worthy of me&apos; (Matt 10:37-38). Zedekiah tried to preserve family relationships by disobeying YHWH and lost them all; genuine surrender to YHWH&apos;s purposes would have preserved them.</p>",
    "24": "<p>Zedekiah warns Jeremiah to keep the conversation secret. The privatization of truth — the king wants the prophetic word but not the public accountability. Jesus repeatedly exposed hidden things: &apos;whatever you have said in the dark will be heard in the daylight, and what you have whispered in the ear in the inner rooms will be proclaimed from the rooftops&apos; (Luke 12:3). Secrets about accountability before God are ultimately exposed.</p>",
    "25": "<p>The officials threatening to question Jeremiah about his conversation with the king. The dual pressure — from the king to be silent, from the officials to disclose. Jesus faced the same: the high priest&apos;s interrogation (John 18:19-23) and Pilate&apos;s questioning (John 18:33-38; 19:9-11) — multiple authorities each demanding a different account.</p>",
    "26": "<p>Jeremiah is instructed to give a partial but not false answer: he was pleading to stay in the court rather than Jonathan&apos;s house. Prudential discretion in the face of hostile questioning. Jesus similarly gave answers that did not condemn the questioner unnecessarily: &apos;the things that are Caesar&apos;s to Caesar and to God the things that are God&apos;s&apos; (Matt 22:21) — a response that neither betrayed his questioners nor compromised his teaching.</p>",
    "27": "<p>The officials questioned Jeremiah; he answered exactly as instructed; they left without learning the full conversation. The protection of truth-telling within appropriate limits. Jesus&apos;s own responses to hostile questioners often left his interrogators &apos;unable to answer him a word, and from that day no one dared ask him any more questions&apos; (Matt 22:46).</p>",
    "28": "<p>&apos;So Jeremiah remained in the court of the guard until the day Jerusalem was captured. He was still there when it was captured.&apos; Jeremiah is present at the catastrophe he prophesied — the witness to the fulfillment. Jesus predicts Jerusalem&apos;s destruction (Matt 24; Luke 19:41-44; Luke 21:20-24) and is the witness through whose name the gospel will be proclaimed to all nations before the end comes (Matt 24:14). He is present through the Spirit in every generation that experiences the judgment he announced.</p>"
  },
  "39": {
    "1": "<p>The ninth year of Zedekiah, tenth month — the exact date of the beginning of the final siege. Jeremiah&apos;s precision with dates is verified by Babylonian records: the Babylonian Chronicles record Nebuchadnezzar&apos;s campaigns and the siege of Jerusalem. Historical precision is itself a theological statement: the God of Israel acts in real time, in datable events, not in mythological timelessness. Jesus&apos;s birth, ministry, death, and resurrection are all dateable — the &apos;fullness of time&apos; (Gal 4:4) is a real historical moment.</p>",
    "2": "<p>The eleventh year, fourth month, ninth day: the city wall is breached. The precision of the catastrophe&apos;s date. The breach of the wall is the end of the city&apos;s self-reliance. Jesus entered Jerusalem knowing the wall would be breached (Luke 19:43-44) and wept over the city. The wall&apos;s breach is the visible fulfillment of everything the prophets had announced.</p>",
    "3": "<p>The Babylonian officials taking their seats at the Middle Gate — the seat of authority transferred from Judah to Babylon in the conquered city. The rulers of this age who seem to hold power ultimately serve the purposes of YHWH. 1 Cor 2:8: &apos;none of the rulers of this age understood it, for if they had, they would not have crucified the Lord of glory.&apos; The Babylonian officials who sit in Jerusalem&apos;s gate, like the Roman officials at Golgotha, are instruments of divine purpose they do not comprehend.</p>",
    "4": "<p>Zedekiah and his soldiers flee at night through the gate between the walls toward the Arabah. The flight from judgment that inevitably fails. Adam and Eve fleeing from YHWH in the garden (Gen 3:8-10) is the original pattern. Jesus makes flight unnecessary: &apos;come to me, all you who are weary and burdened, and I will give you rest&apos; (Matt 11:28). The one who surrenders to Christ has nowhere to flee from because there is nothing to flee from.</p>",
    "5": "<p>The Chaldeans pursue and capture Zedekiah on the plains of Jericho — the city of the first conquest brought to complete reversal. Jericho, where Israel&apos;s conquest began (Josh 6), is now where the last Davidic king is captured. The end of the Davidic monarchy in this geographical location is the dramatic reversal of the conquest narrative. The new Joshua (Yeshua = Joshua) will pass through Jericho again (Luke 18:35-19:10) on his way to Jerusalem — reclaiming what was lost.</p>",
    "6": "<p>Zedekiah&apos;s sons killed before his eyes; the nobles executed. The end of the royal household as Jeremiah predicted. The covenant curse for covenant violation is comprehensive — it reaches the most intimate relationship (children) and the widest institutional structure (the nobles). Jesus&apos;s death is the bearing of this comprehensive curse: &apos;Christ redeemed us from the curse of the law by becoming a curse for us&apos; (Gal 3:13).</p>",
    "7": "<p>&apos;Then he put out Zedekiah&apos;s eyes, bound him in bronze chains, and took him to Babylon.&apos; The blinding of Zedekiah — seeing his sons killed is the last thing he sees; then his eyes are taken. Ezekiel had prophesied: &apos;he will be brought to Babylon but will not see it, though he will die there&apos; (Ezek 12:13). The irony of the king who could not see (would not see) the prophetic word is given a physical counterpart: literal blindness. Jesus restores sight to the blind (John 9:1-7; Luke 4:18); his coming is the reversal of this judgment-blindness.</p>",
    "8": "<p>The burning of the palace and houses, the tearing down of Jerusalem&apos;s walls. The covenant curse enacted: Deut 28:52: &apos;they will lay siege to all the cities throughout your land until the high fortified walls in which you trust fall down.&apos; Jesus&apos;s crucifixion dismantles the wall of hostility between Jew and Gentile: &apos;he himself is our peace, who has made the two groups one and has destroyed the barrier, the dividing wall of hostility&apos; (Eph 2:14). The wall that Jerusalem placed its trust in is destroyed so that a different kind of wall — the body of Christ — can be the meeting point.</p>",
    "9": "<p>The exile of the survivors to Babylon — the deportation that creates the diaspora community. The scattering that precedes the gathering. Jesus sends his disciples into the entire world (Matt 28:19-20) — a diaspora mission that is the inverse of the judgment-exile: instead of being scattered as punishment, the disciples are sent out as mission. The exile&apos;s scattering is redemptively reversed in the great commission&apos;s sending.</p>",
    "10": "<p>&apos;But Nebuzaradan the captain of the guard left in the land of Judah some of the poorest people, who owned nothing, and gave them vineyards and fields at the same time.&apos; The poor inheriting the land. Jesus&apos;s Beatitude: &apos;blessed are the meek, for they will inherit the earth&apos; (Matt 5:5). The powerful are removed and the powerless are given what was taken from them — the covenant justice that operates through reversal. The remnant of the poor who remain in the land are the embodiment of what Jesus announces as the kingdom principle.</p>",
    "11": "<p>Nebuchadnezzar gives specific instructions to protect Jeremiah. The pagan king&apos;s protection of the prophet who announced his victory. This is the divine sovereignty visible through unexpected instruments: YHWH uses the Babylonian king to protect his servant, just as he used Cyrus to restore Israel (Isa 44:28-45:1). Joseph in Pharaoh&apos;s court, Daniel in Nebuchadnezzar&apos;s court, Paul in Roman custody (Phil 1:12-14: &apos;what has happened to me has actually served to advance the gospel&apos;) — God uses pagan structures to preserve and advance his purposes.</p>",
    "12": "<p>&apos;Take him and look after him; do him no harm, but treat him however he requests.&apos; The pagan king&apos;s order of care for the prophet. Jesus is cared for in unexpected places: Egypt (Matt 2:13-15), the household of Mary and Martha (Luke 10:38-42), the provision of a borrowed tomb (John 19:41-42). YHWH provides for his servants through whatever means are available, including the generosity of those outside the covenant community.</p>",
    "13": "<p>Nebuzaradan and the Babylonian commanders carry out the king&apos;s instructions concerning Jeremiah. The execution of the protective order through the military hierarchy. God&apos;s protection operates through chains of command and institutional structures — not only through supernatural intervention. Cornelius the Roman centurion is instructed by an angel to send for Peter (Acts 10:1-8); the protective mechanisms of the Roman legal system are used to advance Paul&apos;s mission (Acts 25:11-12).</p>",
    "14": "<p>Jeremiah handed to Gedaliah son of Ahikam son of Shaphan — the family that has consistently protected Jeremiah (Ahikam saved him from death in 26:24). Released to live among the people. The community of those who receive the prophet: Gedaliah becomes the governor who provides the post-exile space for the remnant to reconstitute. Jesus&apos;s disciples form the community that receives his risen presence (John 20:19-23) — the post-crucifixion gathering that the prophet&apos;s release to his protectors foreshadows.</p>",
    "15": "<p>A word of the LORD to Jeremiah while still in the court of the guard — about Ebed-melech. The imprisoned prophet receives a message about someone outside his cell, concerning a person whose act of faithfulness months earlier is now being rewarded. YHWH&apos;s tracking of covenant faithfulness across time: &apos;God is not unjust; he will not forget your work and the love you have shown him as you have helped his people and continue to help them&apos; (Heb 6:10). The reward of the faithful act is announced in advance.</p>",
    "16": "<p>The oracle to Ebed-melech: I am about to bring disaster on this city — the judgment announced. Even the oracle of personal salvation to the faithful servant is set against the backdrop of coming judgment. Jesus&apos;s words of salvation are similarly set against the backdrop of coming judgment: &apos;whoever believes in him is not condemned, but whoever does not believe stands condemned already&apos; (John 3:18). Salvation is salvation from something real.</p>",
    "17": "<p>&apos;But I will rescue you on that day, declares the LORD, and you will not be handed over to the men you dread.&apos; The personal rescue in the midst of national catastrophe. Jesus&apos;s promise: &apos;not a hair of your head will perish&apos; (Luke 21:18, in the context of the Jerusalem judgment) — the individual protected amid corporate destruction. The protection is personal and specific: Ebed-melech&apos;s rescue is specifically about him, not a general survival statistic.</p>",
    "18": "<p>&apos;I will certainly save you; you will not fall by the sword. You will escape with your life, because you have trusted in me, declares the LORD.&apos; <em>Ki vatachta bi</em>: because you trusted in me. The salvation formula — YHWH&apos;s rescue grounded explicitly in the recipient&apos;s faith/trust. This is the OT&apos;s clearest formulation of salvation by faith outside the Abraham narrative (Gen 15:6). Jesus&apos;s consistent salvation formula: &apos;your faith has healed you&apos; (Mark 5:34; Luke 17:19); &apos;whoever believes in him shall not perish but have eternal life&apos; (John 3:16). The Ethiopian foreigner&apos;s trust in YHWH is the precise mechanism of his personal deliverance.</p>"
  },
  "40": {
    "1": "<p>The word that came to Jeremiah after his release — YHWH speaks to him again in freedom. The word of the LORD continues to come after the worst has happened: the city has fallen, the temple is burned, the king is blinded and in chains. Nothing silences the word — &apos;the word of God is not chained&apos; (2 Tim 2:9, Paul writing from prison). The post-catastrophe word is the word of new possibility.</p>",
    "2": "<p>&apos;The LORD your God pronounced this disaster on this place.&apos; A Babylonian military commander articulates the theology of the conquest better than many of Judah&apos;s prophets: YHWH did this; it was announced; it has happened. The pagan centurion at the cross has the same moment of clarity: &apos;surely this man was the Son of God&apos; (Mark 15:39); &apos;certainly this man was innocent&apos; (Luke 23:47). The outsider often perceives what the insider refuses to acknowledge: the divine causation behind the event.</p>",
    "3": "<p>&apos;The LORD has brought it about and done exactly as he said, because you sinned against the LORD and did not obey his voice.&apos; The Babylonian commander&apos;s theological summary of the entire book of Jeremiah. He has grasped what generations of Israelites refused to hear: the connection between covenant unfaithfulness and the coming disaster. Jesus&apos;s post-resurrection explanation of Scripture follows the same pattern: &apos;was it not necessary for the Messiah to suffer these things and then enter his glory?&apos; (Luke 24:26). Both the commander and the risen Jesus are giving theological sense to what has happened.</p>",
    "4": "<p>&apos;But now, I am releasing you this very day from the chains on your hands.&apos; The chains removed — the imprisoned prophet set free. Paul describes the gospel as freedom from slavery: &apos;it is for freedom that Christ has set us free. Stand firm, then, and do not let yourselves be burdened again by a yoke of slavery&apos; (Gal 5:1). The release from chains is the enacted sign of what the gospel produces: liberation from what has bound the person.</p>",
    "5": "<p>The choice given to Jeremiah: come to Babylon under the commander&apos;s protection, or go wherever he pleases. Freedom of choice offered by a pagan military authority. Jesus similarly offers genuine choice: &apos;come to me, all you who are weary and burdened&apos; (Matt 11:28) — the invitation is genuine, not coerced. The gospel offer does not remove human agency; it extends an invitation that must be freely received.</p>",
    "6": "<p>Jeremiah chooses to stay with the remnant in the land — to be with the poorest of the people who remain. The choice of solidarity with the most vulnerable. Jesus&apos;s incarnation is the supreme choice of solidarity: &apos;the Word became flesh and made his dwelling among us&apos; (John 1:14); &apos;though he was rich, yet for your sake he became poor, so that you through his poverty might become rich&apos; (2 Cor 8:9). The prophet who could have had Babylonian protection chooses the marginalized remnant.</p>",
    "7": "<p>The commanders of the forces in the open country hear that the king of Babylon has appointed Gedaliah as governor. The scattered military units reconstituting around a new center of authority. Jesus&apos;s resurrection creates a new gathering point: &apos;he appeared to more than five hundred of the brothers and sisters at the same time&apos; (1 Cor 15:6); the scattered disciples reassemble around the risen one. The post-catastrophe reconstitution always requires a new center of authority.</p>",
    "8": "<p>The commanders come to Gedaliah at Mizpah. Mizpah (&apos;watchtower&apos;) was a historic gathering place for Israel (1 Sam 7:5-12; 10:17). The remnant gathering at a place whose name means &apos;watching.&apos; Jesus teaches his disciples to watch: &apos;therefore keep watch, because you do not know on what day your Lord will come&apos; (Matt 24:42). The watching community gathered at Mizpah is a shadow of the watching community gathered in expectation of the return.</p>",
    "9": "<p>&apos;Do not be afraid to serve the Chaldeans. Settle in the land and serve the king of Babylon, and it will go well with you.&apos; The pragmatic advice to the remnant: live in the new reality. Paul&apos;s advice to the early Christians in the Roman empire follows a similar pattern: &apos;let everyone be subject to the governing authorities, for there is no authority except that which God has established&apos; (Rom 13:1). Living faithfully under foreign authority is not compromise — it can be covenant faithfulness in a new context.</p>",
    "10": "<p>Gedaliah stays at Mizpah to represent the remnant before the Chaldeans; the people are to harvest the summer fruit, oil, and wine. The ordinary work of harvest in the midst of political catastrophe. Jesus&apos;s parable of the talents (Matt 25:14-30) has the same principle: keep working with what has been entrusted to you until the master returns. The harvest continues even in the post-catastrophe moment.</p>",
    "11": "<p>Jews living in Moab, Ammon, Edom, and other lands hear that Babylon has allowed a remnant to remain in Judah. The diaspora learning that a return is possible. The prodigal son hears from afar that there is provision at his father&apos;s house (Luke 15:17-20: &apos;when he came to his senses, he said: how many of my father&apos;s hired servants have food to spare, and here I am starving to death! I will set out and go back to my father&apos;). The hearing of good news from the homeland triggers the return of the scattered.</p>",
    "12": "<p>The scattered Jews return from all the places to which they had been scattered, come to Judah, and gather a large harvest. The harvest after the return — the reversal of the desolation. Joel 2:24-25: &apos;the threshing floors will be filled with grain; the vats will overflow with new wine and oil. I will repay you for the years the locusts have eaten.&apos; The gathered harvest of the remnant is the temporal fulfillment that points toward the eschatological harvest — the great gathering that Jesus announces (Matt 13:30: &apos;at harvest time I will tell the harvesters: first collect the weeds ... then gather the wheat&apos;).</p>",
    "13": "<p>Johanan and the commanders warn Gedaliah of Baalis&apos;s assassination plot through Ishmael. The danger that undermines the fragile restoration — the internal threat from those who want to destroy what has been rebuilt. Jesus anticipates the internal threats to his flock: &apos;wolves will come in among you and will not spare the flock. Even from your own number men will arise and distort the truth in order to draw away disciples after them&apos; (Acts 20:29-30). The post-catastrophe community is always vulnerable to internal subversion.</p>",
    "14": "<p>Gedaliah is warned: Baalis king of Ammon has sent Ishmael to kill you. The specific, credible intelligence that the governor refuses to act on. Jesus warns his disciples about specific dangers: &apos;I am sending you out like sheep among wolves. Therefore be as shrewd as snakes and as innocent as doves&apos; (Matt 10:16). Godly leadership requires discerning specific threats, not just general vigilance.</p>",
    "15": "<p>Johanan offers to kill Ishmael secretly to prevent the assassination. The pragmatic proposal — neutralize the threat preemptively. Jesus&apos;s response to Peter cutting off the servant&apos;s ear (John 18:10-11: &apos;put your sword away! Shall I not drink the cup the Father has given me?&apos;) addresses exactly this pragmatic-violence impulse. Preemptive violence, even in service of protecting the righteous, is not the way of the kingdom.</p>",
    "16": "<p>Gedaliah refuses Johanan&apos;s offer: &apos;You must not do this. What you are saying about Ishmael is not true.&apos; The fatal miscalculation — trusting where distrust was warranted. Peter&apos;s rebuke to Jesus about the cross (&apos;Never, Lord! This shall never happen to you!&apos;, Matt 16:22) comes from a similar refusal to believe the credible warning. Both Gedaliah and Peter are refusing a painful truth out of what looks like faith but is actually denial. The consequences of Gedaliah&apos;s refusal will unfold in ch. 41.</p>"
  }
}

def main():
    existing = load_comm('mkt-christ', 'jeremiah')
    merge_comm(existing, JER_CHRIST)
    save_comm('mkt-christ', 'jeremiah', existing)

    out = json.loads((ROOT / 'data/commentary/mkt-christ/jeremiah.json').read_text())
    il  = json.loads((ROOT / 'data/interlinear/jeremiah.json').read_text())

    all_ok = True
    for ch in [37, 38, 39, 40]:
        ck = str(ch)
        missing = set(il.get(ck, {}).keys()) - set(out.get(ck, {}).keys())
        if missing:
            print(f'ch {ch} STILL MISSING: {sorted(missing, key=int)}')
            all_ok = False
        else:
            print(f'ch {ch}: complete ({len(out.get(ck, {}))} verses)')
    if all_ok:
        print('All verses present')

if __name__ == '__main__':
    main()
